import{_ as d,o as e,c as r,aS as o}from"./chunks/framework.DdSiWJCR.js";const p=JSON.parse('{"title":"Docker指令速查手册","description":"","frontmatter":{},"headers":[],"relativePath":"服务器运维/docker/Docker指令速查手册.md","filePath":"服务器运维/docker/Docker指令速查手册.md","lastUpdated":null}'),c={name:"服务器运维/docker/Docker指令速查手册.md"};function a(n,t,i,h,k,s){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="docker指令速查手册" tabindex="-1">Docker指令速查手册 <a class="header-anchor" href="#docker指令速查手册" aria-label="Permalink to &quot;Docker指令速查手册&quot;">​</a></h1><h2 id="_1-基础容器状态操作" tabindex="-1">1. 基础容器状态操作 <a class="header-anchor" href="#_1-基础容器状态操作" aria-label="Permalink to &quot;1. 基础容器状态操作&quot;">​</a></h2><p>场景：容器创建、启停、暂停、删除等生命周期管理</p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>docker run -d --name mynginx nginx</code></td><td>创建并后台运行一个容器</td></tr><tr><td><code>docker start mynginx</code></td><td>启动已停止的容器</td></tr><tr><td><code>docker stop mynginx</code></td><td>优雅停止运行中的容器</td></tr><tr><td><code>docker restart mynginx</code></td><td>重启容器</td></tr><tr><td><code>docker pause mynginx</code></td><td>暂停容器内全部进程</td></tr><tr><td><code>docker unpause mynginx</code></td><td>恢复已暂停的容器</td></tr><tr><td><code>docker rm mynginx</code></td><td>删除已停止的容器</td></tr><tr><td><code>docker rm -f mynginx</code></td><td>⚠️强制删除正在运行的容器</td></tr></tbody></table><hr><h2 id="_2-镜像管理" tabindex="-1">2. 镜像管理 <a class="header-anchor" href="#_2-镜像管理" aria-label="Permalink to &quot;2. 镜像管理&quot;">​</a></h2><p>场景：拉取、构建、打标、推送、删除本地镜像</p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>docker pull nginx:alpine</code></td><td>从镜像仓库拉取指定版本镜像</td></tr><tr><td><code>docker images</code></td><td>列出本地全部镜像</td></tr><tr><td><code>docker image ls</code></td><td>列出本地全部镜像（新版标准写法）</td></tr><tr><td><code>docker rmi nginx:alpine</code></td><td>删除指定镜像</td></tr><tr><td><code>docker rmi $(docker images -q)</code></td><td>⚠️删除本地所有镜像（高危慎用）</td></tr><tr><td><code>docker build -t myapp:v1 .</code></td><td>基于当前目录 Dockerfile 构建镜像并打标签</td></tr><tr><td><code>docker tag nginx:alpine myrepo/nginx:v1</code></td><td>为已有镜像新增仓库标签</td></tr><tr><td><code>docker push myrepo/nginx:v1</code></td><td>将镜像推送到远程私有仓库</td></tr><tr><td><code>docker system prune -a</code></td><td>⚠️一键清理未使用镜像、容器、网络（谨慎执行）</td></tr></tbody></table><hr><h2 id="_3-容器信息查看与日志排查" tabindex="-1">3. 容器信息查看与日志排查 <a class="header-anchor" href="#_3-容器信息查看与日志排查" aria-label="Permalink to &quot;3. 容器信息查看与日志排查&quot;">​</a></h2><p>场景：查看运行状态、资源占用、日志、进程用于问题排查</p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>docker ps</code></td><td>仅列出正在运行的容器</td></tr><tr><td><code>docker ps -a</code></td><td>列出所有容器（包含已停止）</td></tr><tr><td><code>docker stats</code></td><td>实时监控所有容器 CPU、内存、网络资源占用</td></tr><tr><td><code>docker logs mynginx</code></td><td>查看容器全部历史日志</td></tr><tr><td><code>docker logs -f mynginx</code></td><td>实时持续跟踪容器日志输出</td></tr><tr><td><code>docker logs --tail 100 mynginx</code></td><td>只查看容器最后 100 行日志</td></tr><tr><td><code>docker inspect mynginx</code></td><td>JSON 格式输出容器完整配置详情</td></tr><tr><td><code>docker top mynginx</code></td><td>查看容器内部运行的进程列表</td></tr></tbody></table><hr><h2 id="_4-进入容器调试" tabindex="-1">4. 进入容器调试 <a class="header-anchor" href="#_4-进入容器调试" aria-label="Permalink to &quot;4. 进入容器调试&quot;">​</a></h2><p>场景：登录容器内部修改配置、调试程序</p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>docker exec -it mynginx /bin/bash</code></td><td>交互式进入容器 bash 终端（标准推荐）</td></tr><tr><td><code>docker exec -it mynginx /bin/sh</code></td><td>进入 alpine 极简镜像（无 bash）</td></tr><tr><td><code>docker exec mynginx ls /app</code></td><td>在容器内执行单条命令，不开启交互终端</td></tr><tr><td><code>docker attach mynginx</code></td><td>挂载容器标准输出流（极少使用，退出易停容器）</td></tr></tbody></table><hr><h2 id="_5-网络管理" tabindex="-1">5. 网络管理 <a class="header-anchor" href="#_5-网络管理" aria-label="Permalink to &quot;5. 网络管理&quot;">​</a></h2><p>场景：端口映射、自定义网桥、容器互通、网络查询</p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>docker network ls</code></td><td>列出本地所有 Docker 网络</td></tr><tr><td><code>docker network create mynet</code></td><td>创建自定义桥接网络</td></tr><tr><td><code>docker run --network mynet nginx</code></td><td>指定自定义网络启动容器</td></tr><tr><td><code>docker network connect mynet mynginx</code></td><td>将运行中的容器加入指定网络</td></tr><tr><td><code>docker network disconnect mynet mynginx</code></td><td>将容器从网络中断开</td></tr><tr><td><code>docker network rm mynet</code></td><td>删除闲置自定义网络</td></tr><tr><td><code>docker network inspect mynet</code></td><td>查看网络详细配置与接入容器</td></tr><tr><td><code>docker port mynginx</code></td><td>查看容器端口映射关系</td></tr><tr><td><code>docker run -p 8080:80 nginx</code></td><td>端口映射：宿主机 8080 转发容器 80 端口</td></tr></tbody></table><hr><h2 id="_6-数据持久化与文件拷贝" tabindex="-1">6. 数据持久化与文件拷贝 <a class="header-anchor" href="#_6-数据持久化与文件拷贝" aria-label="Permalink to &quot;6. 数据持久化与文件拷贝&quot;">​</a></h2><p>场景：Volume 持久化存储、宿主机目录挂载、容器内外文件互传</p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>docker volume ls</code></td><td>列出所有数据卷</td></tr><tr><td><code>docker volume create mydata</code></td><td>创建命名持久化数据卷</td></tr><tr><td><code>docker volume inspect mydata</code></td><td>查看数据卷存储路径与详情</td></tr><tr><td><code>docker volume rm mydata</code></td><td>删除指定数据卷</td></tr><tr><td><code>docker run -v mydata:/app/data nginx</code></td><td>挂载数据卷至容器目录</td></tr><tr><td><code>docker run -v /host/path:/container/path nginx</code></td><td>绑定挂载宿主机本地目录到容器</td></tr><tr><td><code>docker run --mount source=mydata,target=/app/data nginx</code></td><td>标准 mount 语法挂载数据卷（可读性更高）</td></tr><tr><td><code>docker cp /host/file mynginx:/app/</code></td><td>宿主机文件复制到容器内</td></tr><tr><td><code>docker cp mynginx:/app/file /host/</code></td><td>容器内文件复制到宿主机</td></tr></tbody></table><hr><h2 id="_7-资源清理与磁盘维护" tabindex="-1">7. 资源清理与磁盘维护 <a class="header-anchor" href="#_7-资源清理与磁盘维护" aria-label="Permalink to &quot;7. 资源清理与磁盘维护&quot;">​</a></h2><p>场景：定期清理无用容器、镜像、网络、数据卷释放磁盘</p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>docker container prune</code></td><td>删除所有已停止的容器</td></tr><tr><td><code>docker image prune</code></td><td>清理无标签悬空镜像</td></tr><tr><td><code>docker image prune -a</code></td><td>删除所有未被容器引用的镜像</td></tr><tr><td><code>docker volume prune</code></td><td>删除未使用的数据卷（⚠️ 会丢失持久化数据）</td></tr><tr><td><code>docker network prune</code></td><td>删除未被容器使用的闲置网络</td></tr><tr><td><code>docker system prune</code></td><td>基础清理：停止容器、悬空镜像、闲置网络</td></tr><tr><td><code>docker system prune -a</code></td><td>深度全量清理，包含全部未使用镜像（慎用）</td></tr><tr><td><code>docker system df</code></td><td>统计 Docker 整体磁盘占用明细</td></tr></tbody></table><hr><h2 id="_8-镜像离线迁移-导入导出" tabindex="-1">8. 镜像离线迁移（导入导出） <a class="header-anchor" href="#_8-镜像离线迁移-导入导出" aria-label="Permalink to &quot;8. 镜像离线迁移（导入导出）&quot;">​</a></h2><p>场景：内网离线环境镜像打包、迁移、恢复</p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>docker save -o myapp.tar myapp:v1</code></td><td>将完整镜像（含分层历史）导出 tar 包</td></tr><tr><td><code>docker load -i myapp.tar</code></td><td>从 tar 文件恢复完整镜像</td></tr><tr><td><code>docker export -o container.tar mynginx</code></td><td>导出容器单层快照（丢失镜像分层历史）</td></tr><tr><td><code>docker import container.tar mynewimage:v1</code></td><td>将容器快照导入生成新镜像</td></tr></tbody></table><hr><h2 id="_9-docker-compose-多容器编排" tabindex="-1">9. Docker Compose 多容器编排 <a class="header-anchor" href="#_9-docker-compose-多容器编排" aria-label="Permalink to &quot;9. Docker Compose 多容器编排&quot;">​</a></h2><p>场景：一键管理多服务应用（前端、后端、数据库等）</p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>docker-compose up -d</code></td><td>后台启动 compose 所有服务</td></tr><tr><td><code>docker-compose down</code></td><td>停止并删除所有服务容器（保留数据卷）</td></tr><tr><td><code>docker-compose ps</code></td><td>查看 compose 各服务运行状态</td></tr><tr><td><code>docker-compose logs -f</code></td><td>实时查看全部服务日志</td></tr><tr><td><code>docker-compose logs -f service_name</code></td><td>仅查看指定服务实时日志</td></tr><tr><td><code>docker-compose restart</code></td><td>重启全部服务</td></tr><tr><td><code>docker-compose restart service_name</code></td><td>单独重启某一个服务</td></tr><tr><td><code>docker-compose exec service_name /bin/bash</code></td><td>进入指定服务容器交互终端</td></tr><tr><td><code>docker-compose build</code></td><td>重新构建 compose 自定义服务镜像</td></tr><tr><td><code>docker-compose pull</code></td><td>拉取所有服务最新镜像</td></tr><tr><td><code>docker-compose up -d --scale web=3</code></td><td>对 web 服务扩容至 3 个运行实例</td></tr></tbody></table><hr><h2 id="_10-高频组合实用命令" tabindex="-1">10. 高频组合实用命令 <a class="header-anchor" href="#_10-高频组合实用命令" aria-label="Permalink to &quot;10. 高频组合实用命令&quot;">​</a></h2><p>场景：一条命令批量操作容器 / 镜像，提升运维效率</p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>docker stop $(docker ps -q)</code></td><td>一次性停止所有正在运行的容器</td></tr><tr><td><code>docker rm $(docker ps -aq)</code></td><td>删除本地全部容器（含已停止）</td></tr><tr><td><code>docker rmi $(docker images -q)</code></td><td>删除本地全部镜像</td></tr><tr><td><code>docker stop $(docker ps -q) &amp;&amp; docker rm $(docker ps -aq)</code></td><td>停止并清空所有容器</td></tr><tr><td><code>docker exec -it $(docker ps -q -f name=nginx) /bin/bash</code></td><td>通过名称过滤直接进入 nginx 容器</td></tr><tr><td><code>docker logs -f --tail 50 $(docker ps -q -f status=running)</code></td><td>查看所有运行容器最后 50 行实时日志</td></tr></tbody></table><hr>',41)])])}const l=d(c,[["render",a]]);export{p as __pageData,l as default};
